interface ExecutorIdentityProps {
  mode?: ConversationTab['mode'];
  isActive?: boolean;
}

export default function ExecutorIdentity({ mode, isActive }: ExecutorIdentityProps) {
  const opacity = isActive ? 0.8 : 0.3;

  if (mode === 'claude_terminal') {
    return (
      <span
        title="Claude Code"
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
          width: 14,
          height: 14,
          color: `rgba(255, 255, 255, ${opacity})`,
          transition: 'color 0.15s',
          pointerEvents: 'none',
        }}
      >
        <ClaudeMark size={13} />
      </span>
    );
  }

  if (mode === 'codex_terminal') {
    return (
      <span
        title="Codex"
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
          width: 14,
          height: 14,
          color: `rgba(255, 255, 255, ${opacity})`,
          transition: 'color 0.15s',
          pointerEvents: 'none',
        }}
      >
        <OpenAIMark size={13} />
      </span>
    );
  }

  if (mode === 'concurrent') {
    return (
      <span
        title="Concurrent"
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexShrink: 0,
          width: 14,
          height: 14,
          color: `rgba(255, 255, 255, ${opacity})`,
          fontSize: 9,
          fontWeight: 700,
          fontFamily: 'ui-monospace, monospace',
          letterSpacing: '-0.05em',
          pointerEvents: 'none',
          transition: 'color 0.15s',
        }}
      >
        //
      </span>
    );
  }

  return null;
}
